/**
 * Graph — compact SVG charts for React PDF documents.
 *
 * @registryTitle PDF Graph
 * @registryDescription Lightweight bar graph rendered with React PDF SVG primitives.
 * @registryCategory data
 * @registryDemos basic=Basic, empty=Empty
 */

import {
  Svg,
  Rect,
  G,
  Text as SvgText,
  View,
  Text,
  StyleSheet,
} from "@react-pdf/renderer";
import type { Style } from "@react-pdf/types";
import {
  mergePdfStyles,
  type PdfStyleInput,
  usePdfTheme,
} from "@/lib/pdf-theme";

export interface PdfGraphDatum {
  label: string;
  value: number;
}

export interface PdfGraphProps {
  data: PdfGraphDatum[];
  width?: number;
  height?: number;
  emptyText?: string;
  style?: PdfStyleInput;
}

export function PdfGraph({
  data,
  width = 320,
  height = 140,
  emptyText = "No graph data",
  style,
}: PdfGraphProps) {
  const theme = usePdfTheme();
  const styles = StyleSheet.create({
    empty: {
      color: theme.colors.mutedForeground,
      fontFamily: theme.typography.fontFamily,
      fontSize: theme.typography.sm,
    } as Style,
  });
  if (data.length === 0) return <Text style={styles.empty}>{emptyText}</Text>;

  const maxValue = Math.max(...data.map((item) => item.value), 1);
  const padding = 20;
  const chartHeight = height - padding * 2;
  const slotWidth = (width - padding * 2) / data.length;
  const barWidth = Math.max(8, slotWidth * 0.55);
  const svgTextStyle = { fontSize: 7 } as never;

  return (
    <View style={mergePdfStyles(style)}>
      <Svg width={width} height={height}>
        <Rect x={0} y={0} width={width} height={height} fill="transparent" />
        {data.map((item, index) => {
          const barHeight = (item.value / maxValue) * chartHeight;
          const x = padding + index * slotWidth + (slotWidth - barWidth) / 2;
          const y = height - padding - barHeight;
          return (
            <G key={item.label}>
              <Rect
                x={x}
                y={y}
                width={barWidth}
                height={barHeight}
                fill={theme.colors.primary}
              />
              <SvgText
                x={x + barWidth / 2}
                y={height - 8}
                textAnchor="middle"
                fill={theme.colors.mutedForeground}
                style={svgTextStyle}
              >
                {item.label}
              </SvgText>
              <SvgText
                x={x + barWidth / 2}
                y={Math.max(10, y - 4)}
                textAnchor="middle"
                fill={theme.colors.foreground}
                style={svgTextStyle}
              >
                {item.value}
              </SvgText>
            </G>
          );
        })}
      </Svg>
    </View>
  );
}

/**
 * PDF Theme — shared theme tokens and helpers for edbn/ui PDF components.
 *
 * @registryTitle PDF Theme
 * @registryDescription Theme provider, default tokens, and style helpers for PDF components.
 * @registryVariant pdf
 * @registryType registry:lib
 */

import * as React from "react";
import type { Style } from "@react-pdf/types";

// ---- TYPES -----------------------------------------------------------------

export interface PdfTheme {
  colors: {
    background: string;
    foreground: string;
    mutedForeground: string;
    border: string;
    primary: string;
    primaryForeground: string;
    muted: string;
    destructive: string;
    warning: string;
    success: string;
  };
  spacing: {
    page: number;
    section: number;
    gap: number;
    sm: number;
    md: number;
    lg: number;
  };
  radii: {
    sm: number;
    md: number;
    lg: number;
  };
  typography: {
    fontFamily: string;
    monoFontFamily: string;
    xs: number;
    sm: number;
    base: number;
    lg: number;
    xl: number;
    xxl: number;
  };
}

export type PdfStyleInput = Style | Style[] | null | undefined | false;

// ---- DEFAULT THEME ---------------------------------------------------------

export const defaultPdfTheme: PdfTheme = {
  colors: {
    background: "#ffffff",
    foreground: "#111827",
    mutedForeground: "#6b7280",
    border: "#d1d5db",
    primary: "#2563eb",
    primaryForeground: "#ffffff",
    muted: "#f3f4f6",
    destructive: "#dc2626",
    warning: "#b45309",
    success: "#15803d",
  },
  spacing: {
    page: 36,
    section: 16,
    gap: 10,
    sm: 6,
    md: 10,
    lg: 16,
  },
  radii: {
    sm: 4,
    md: 7,
    lg: 10,
  },
  typography: {
    fontFamily: "Helvetica",
    monoFontFamily: "Courier",
    xs: 8,
    sm: 9,
    base: 10.5,
    lg: 13,
    xl: 18,
    xxl: 28,
  },
};

// ---- CONTEXT ---------------------------------------------------------------

const PdfThemeContext = React.createContext<PdfTheme>(defaultPdfTheme);

export interface PdfThemeProviderProps {
  theme?: Partial<PdfTheme>;
  children: React.ReactNode;
}

function mergeTheme(theme?: Partial<PdfTheme>): PdfTheme {
  if (!theme) return defaultPdfTheme;
  return {
    colors: { ...defaultPdfTheme.colors, ...theme.colors },
    spacing: { ...defaultPdfTheme.spacing, ...theme.spacing },
    radii: { ...defaultPdfTheme.radii, ...theme.radii },
    typography: { ...defaultPdfTheme.typography, ...theme.typography },
  };
}

export function PdfThemeProvider({ theme, children }: PdfThemeProviderProps) {
  const resolvedTheme = React.useMemo(() => mergeTheme(theme), [theme]);
  return (
    <PdfThemeContext.Provider value={resolvedTheme}>
      {children}
    </PdfThemeContext.Provider>
  );
}

export function usePdfTheme(): PdfTheme {
  return React.useContext(PdfThemeContext) ?? defaultPdfTheme;
}

// ---- STYLE HELPERS ---------------------------------------------------------

export function mergePdfStyles(...styles: PdfStyleInput[]): Style[] {
  return styles.flatMap((style) => {
    if (!style) return [];
    return Array.isArray(style) ? style.filter(Boolean) : [style];
  });
}

export function getToneColor(theme: PdfTheme, tone?: string): string {
  switch (tone) {
    case "primary":
      return theme.colors.primary;
    case "muted":
      return theme.colors.mutedForeground;
    case "destructive":
      return theme.colors.destructive;
    case "warning":
      return theme.colors.warning;
    case "success":
      return theme.colors.success;
    default:
      return theme.colors.foreground;
  }
}
